const data = {
    baseCostPsf: {
        'Residential House': { 'Standard': 180, 'Mid-Range': 280, 'Premium': 450 },
        'Commercial Office': { 'Standard': 220, 'Mid-Range': 380, 'Premium': 600 },
        'Industrial Warehouse': { 'Standard': 90, 'Mid-Range': 160, 'Premium': 280 },
        'Multi-Family Apartment': { 'Standard': 190, 'Mid-Range': 300, 'Premium': 480 }
    },
    damageSeverityMultipliers: {
        1: 0.15, // Minor
        2: 0.35, // Moderate
        3: 0.60, // Severe
        4: 0.85, // Extensive
        5: 1.00  // Catastrophic (Total Loss)
    },
    disasterComplexityMultipliers: {
        'Hurricane/Typhoon': 1.10, // Wind, water, debris removal, specific engineering
        'Earthquake': 1.25,      // Structural integrity, specialized engineering, foundation work
        'Flood': 1.15,           // Water damage, mold remediation, drying, potential foundation issues
        'Wildfire': 1.20,        // Smoke/ash remediation, structural damage, specialized cleaning
        'Tornado': 1.18,         // Localized intense structural damage, debris removal
        'Severe Winter Storm': 1.05 // Ice/snow load, pipe bursts, localized structural failure
    },
    laborRateMultipliers: {
        'High Cost Urban': 1.30,
        'Average Suburban': 1.00,
        'Low Cost Rural': 0.80
    },
    // Time in months per 1000 sq ft for a standard rebuild, then adjusted.
    // Base time assumes 'Mid-Range' for common types at a 'Moderate' severity.
    baseTimePsfMonths: {
        'Residential House': 0.6,
        'Commercial Office': 0.8,
        'Industrial Warehouse': 0.4,
        'Multi-Family Apartment': 0.7
    },
    timeSeverityMultipliers: {
        1: 0.3, // Minor
        2: 0.7, // Moderate
        3: 1.2, // Severe
        4: 1.8, // Extensive
        5: 2.5  // Catastrophic
    },
    timeDisasterComplexityMultipliers: {
        'Hurricane/Typhoon': 1.1,
        'Earthquake': 1.3,
        'Flood': 1.15,
        'Wildfire': 1.2,
        'Tornado': 1.15,
        'Severe Winter Storm': 1.05
    }
};

// Input validation and defaults
const buildingType = inputs.buildingType || 'Residential House';
const squareFootage = Math.max(100, parseFloat(inputs.squareFootage) || 0);
const disasterType = inputs.disasterType || 'Hurricane/Typhoon';
const damageSeverityScale = Math.min(5, Math.max(1, parseInt(inputs.damageSeverityScale) || 3));
const materialQuality = inputs.materialQuality || 'Mid-Range';
const laborRateRegion = inputs.laborRateRegion || 'Average Suburban';
const projectManagementFeePercentage = Math.min(20, Math.max(5, parseFloat(inputs.projectManagementFeePercentage) || 12));
const contingencyFundPercentage = Math.min(30, Math.max(5, parseFloat(inputs.contingencyFundPercentage) || 15));

// Step 1: Determine Base Cost per Square Foot for full replacement
const baseCostPsfForTypeQuality = data.baseCostPsf[buildingType]?.[materialQuality] || 250; // Fallback to a reasonable average

// Step 2: Calculate Initial Total Replacement Value
const initialTotalReplacementValue = baseCostPsfForTypeQuality * squareFootage;

// Step 3: Apply Damage Severity Multiplier to get estimated direct damage cost
const damageMultiplier = data.damageSeverityMultipliers[damageSeverityScale];
const directDamageCost = initialTotalReplacementValue * damageMultiplier;

// Step 4: Apply Disaster Type Complexity Multiplier
const disasterComplexityFactor = data.disasterComplexityMultipliers[disasterType] || 1.0;
const adjustedDamageCost = directDamageCost * disasterComplexityFactor;

// Step 5: Split Adjusted Damage Cost into Material and Labor Components (approximate split)
const materialCostComponent = adjustedDamageCost * 0.6; // Assuming 60% materials
let laborCostComponent = adjustedDamageCost * 0.4;  // Assuming 40% labor

// Step 6: Apply Regional Labor Rate Multiplier to Labor Component
const laborRateFactor = data.laborRateMultipliers[laborRateRegion] || 1.0;
laborCostComponent *= laborRateFactor;

// Step 7: Calculate Total Direct Rebuild Cost (Materials + Adjusted Labor)
const totalDirectRebuildCost = materialCostComponent + laborCostComponent;

// Step 8: Add Project Management Fee
const projectManagementFee = totalDirectRebuildCost * (projectManagementFeePercentage / 100);

// Step 9: Calculate Subtotal before Contingency
const subtotalBeforeContingency = totalDirectRebuildCost + projectManagementFee;

// Step 10: Add Contingency Fund
const contingencyAmount = subtotalBeforeContingency * (contingencyFundPercentage / 100);

// Step 11: Calculate Final Total Rebuild Cost
const totalRebuildCost = subtotalBeforeContingency + contingencyAmount;

// Step 12: Calculate Estimated Rebuild Time (in months)
const baseTime = data.baseTimePsfMonths[buildingType] || 0.6;
const timeSeverityFactor = data.timeSeverityMultipliers[damageSeverityScale] || 1.0;
const timeDisasterFactor = data.timeDisasterComplexityMultipliers[disasterType] || 1.0;

let estimatedRebuildTime = (baseTime * (squareFootage / 1000)) * timeSeverityFactor * timeDisasterFactor;
estimatedRebuildTime = Math.max(0.5, Math.min(estimatedRebuildTime, 36)); // Cap time between 0.5 and 36 months

return {
    totalRebuildCost: totalRebuildCost,
    materialCost: materialCostComponent,
    laborCost: laborCostComponent,
    contingencyAmount: contingencyAmount,
    estimatedRebuildTime: estimatedRebuildTime
};
